"""
Parameterized generator for GH947_pymc_7695.

Source PR:    https://github.com/pymc-devs/pymc/pull/7695
Source Issue: N/A

Seed varies: renames 'accept' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH947_pymc_7695'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH947_pymc_7695'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('accept', 'accept' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH947_pymc_7695',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'pymc-devs/pymc',
                "pr_number": 7695,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/pymc-devs/pymc/pull/7695",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'pymc/sampling/jax.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport logging\nimport os\nimport re\n\nfrom collections.abc import Callable, Sequence\nfrom datetime import datetime\nfrom functools import partial\nfrom types import ModuleType\nfrom typing import Any, Literal\n\nimport arviz as az\nimport jax\nimport jax.numpy as jnp\nimport numpy as np\nimport pytensor.tensor as pt\n\nfrom arviz.data.base import make_attrs\nfrom jax.lax import scan\nfrom numpy.typing import ArrayLike\nfrom pytensor.compile import SharedVariable, Supervisor, mode\nfrom pytensor.graph.basic import graph_inputs\nfrom pytensor.graph.fg import FunctionGraph\nfrom pytensor.graph.replace import clone_replace\nfrom pytensor.link.jax.dispatch import jax_funcify\nfrom pytensor.raise_op import Assert\nfrom pytensor.tensor import TensorVariable\nfrom pytensor.tensor.random.type import RandomType\n\nfrom pymc import Model, modelcontext\nfrom pymc.backends.arviz import (\n    coords_and_dims_for_inferencedata,\n    find_constants,\n    find_observations,\n)\nfrom pymc.distributions.multivariate import PosDefMatrix\nfrom pymc.initial_point import StartDict\nfrom pymc.logprob.utils import CheckParameterValue\nfrom pymc.sampling.mcmc import _init_jitter\nfrom pymc.stats.convergence import log_warnings, run_convergence_checks\nfrom pymc.util import (\n    RandomSeed,\n    RandomState,\n    _get_seeds_per_chain,\n    get_default_varnames,\n)\n\nlogger = logging.getLogger(__name__)\n\nxla_flags_env = os.getenv("XLA_FLAGS", "")\nxla_flags = re.sub(r"--xla_force_host_platform_device_count=.+\\s", "", xla_flags_env).split()\nos.environ["XLA_FLAGS"] = " ".join([f"--xla_force_host_platform_device_count={100}", *xla_flags])\n\n__all__ = (\n    "get_jaxified_graph",\n    "get_jaxified_logp",\n    "sample_blackjax_nuts",\n    "sample_numpyro_nuts",\n)\n\n\n@jax_funcify.register(Assert)\n@jax_funcify.register(CheckParameterValue)\ndef jax_funcify_Assert(op, **kwargs):\n    # Jax does not allow assert whose values aren\'t known during JIT compilation\n    # within it\'s JIT-ed code. Hence we need to make a simple pass through\n    # version of the Assert Op.\n    # https://github.com/google/jax/issues/2273#issuecomment-589098722\n    def assert_fn(value, *inps):\n        return value\n\n    return assert_fn\n\n\n@jax_funcify.register(PosDefMatrix)\ndef jax_funcify_PosDefMatrix(op, **kwargs):\n    def posdefmatrix_fn(value, *inps):\n        no_pos_def = jnp.any(jnp.isnan(jnp.linalg.cholesky(value)))\n        return jnp.invert(no_pos_def)\n\n    return posdefmatrix_fn\n\n\ndef _replace_shared_variables(graph: list[TensorVariable]) -> list[TensorVariable]:\n    """Replace shared variables in graph by their constant values.\n\n    Raises\n    ------\n    ValueError\n        If any shared variable contains default_updates\n    """\n    shared_variables = [var for var in graph_inputs(graph) if isinstance(var, SharedVariable)]\n\n    if any(isinstance(var.type, RandomType) for var in shared_variables):\n        raise ValueError(\n            "Graph contains shared RandomType variables which cannot be safely replaced"\n        )\n\n    if any(var.default_update is not None for var in shared_variables):\n        raise ValueError(\n            "Graph contains shared variables with default_update which cannot be safely replaced."\n        )\n\n    replacements = {var: pt.constant(var.get_value(borrow=True)) for var in shared_variables}\n\n    new_graph = clone_replace(graph, replace=replacements)\n    return new_graph\n\n\ndef get_jaxified_graph(\n    inputs: list[TensorVariable] | None = None,\n    outputs: list[TensorVariable] | None = None,\n) -> Callable[[list[TensorVariable]], list[TensorVariable]]:\n    """Compile a PyTensor graph into an optimized JAX function."""\n    graph = _replace_shared_variables(outputs) if outputs is not None else None\n\n    fgraph = FunctionGraph(inputs=inputs, outputs=graph, clone=True)\n    # We need to add a Supervisor to the fgraph to be able to run the\n    # JAX sequential optimizer without warnings. We made sure there\n    # are no mutable input variables, so we only need to check for\n    # "destroyers". This should be automatically handled by PyTensor\n    # once https://github.com/aesara-devs/aesara/issues/637 is fixed.\n    fgraph.attach_feature(\n        Supervisor(\n            input\n            for input in fgraph.inputs\n            if not (hasattr(fgraph, "destroyers") and fgraph.has_destroyers([input]))\n        )\n    )\n    mode.JAX.optimizer.rewrite(fgraph)\n\n    # We now jaxify the optimized fgraph\n    return jax_funcify(fgraph)\n\n\ndef get_jaxified_logp(model: Model, negative_logp: bool = True) -> Callable[[ArrayLike], jax.Array]:\n    model_logp = model.logp()\n    if not negative_logp:\n        model_logp = -model_logp\n    logp_fn = get_jaxified_graph(inputs=model.value_vars, outputs=[model_logp])\n\n    def logp_fn_wrap(x: ArrayLike) -> jax.Array:\n        return logp_fn(*x)[0]\n\n    return logp_fn_wrap\n\n\ndef _get_log_likelihood(\n    model: Model,\n    samples,\n    backend: Literal["cpu", "gpu"] | None = None,\n    postprocessing_vectorize: Literal["vmap", "scan"] = "scan",\n) -> dict:\n    """Compute log-likelihood for all observations."""\n    elemwise_logp = model.logp(model.observed_RVs, sum=False)\n    jax_fn = get_jaxified_graph(inputs=model.value_vars, outputs=elemwise_logp)\n    result = _postprocess_samples(\n        jax_fn,\n        samples,\n        backend,\n        postprocessing_vectorize=postprocessing_vectorize,\n        donate_samples=False,\n    )\n    return {v.name: r for v, r in zip(model.observed_RVs, result)}\n\n\ndef _device_put(input, device: str):\n    return jax.device_put(input, jax.devices(device)[0])\n\n\ndef _postprocess_samples(\n    jax_fn: Callable,\n    raw_mcmc_samples: list[TensorVariable],\n    postprocessing_backend: Literal["cpu", "gpu"] | None = None,\n    postprocessing_vectorize: Literal["vmap", "scan"] = "vmap",\n    donate_samples: bool = False,\n) -> list[TensorVariable]:\n    if postprocessing_vectorize == "scan":\n        t_raw_mcmc_samples = [jnp.swapaxes(t, 0, 1) for t in raw_mcmc_samples]\n        jax_vfn = jax.vmap(jax_fn)\n        _, outs = scan(\n            lambda _, x: ((), jax_vfn(*x)),\n            (),\n            _device_put(t_raw_mcmc_samples, postprocessing_backend),\n        )\n        return [jnp.swapaxes(t, 0, 1) for t in outs]\n    elif postprocessing_vectorize == "vmap":\n\n        def process_fn(x):\n            return jax.vmap(jax.vmap(jax_fn))(*_device_put(x, postprocessing_backend))\n\n        return jax.jit(process_fn, donate_argnums=0 if donate_samples else None)(raw_mcmc_samples)\n\n    else:\n        raise ValueError(f"Unrecognized postprocessing_vectorize: {postprocessing_vectorize}")\n\n\ndef _get_batched_jittered_initial_points(\n    model: Model,\n    chains: int,\n    initvals: StartDict | Sequence[StartDict | None] | None,\n    random_seed: RandomSeed,\n    logp_fn: Callable[[ArrayLike], jax.Array] | None = None,\n    jitter: bool = True,\n    jitter_max_retries: int = 10,\n) -> np.ndarray | list[np.ndarray]:\n    """Get jittered initial point in format expected by Jax MCMC kernel.\n\n    Parameters\n    ----------\n        logp_fn : Callable[Sequence[np.ndarray]], np.ndarray]\n            Jaxified logp function\n\n    Returns\n    -------\n    out: list of ndarrays\n        list with one item per variable and number of chains as batch dimension.\n        Each item has shape `(chains, *var.shape)`\n    """\n    if logp_fn is None:\n        eval_logp_initial_point = None\n\n    else:\n\n        def eval_logp_initial_point(point: dict[str, np.ndarray]) -> jax.Array:\n            """Wrap logp_fn to conform to _init_jitter logic.\n\n            Wraps jaxified logp function to accept a dict of\n            {model_variable: np.array} key:value pairs.\n            """\n            return logp_fn(point.values())\n\n    initial_points = _init_jitter(\n        model,\n        initvals,\n        seeds=_get_seeds_per_chain(random_seed, chains),\n        jitter=jitter,\n        jitter_max_retries=jitter_max_retries,\n        logp_fn=eval_logp_initial_point,\n    )\n    initial_points_values = [list(initial_point.values()) for initial_point in initial_points]\n    if chains == 1:\n        return initial_points_values[0]\n    return [np.stack(init_state) for init_state in zip(*initial_points_values)]\n\n\ndef _blackjax_inference_loop(\n    seed, init_position, logp_fn, draws, tune, target_accept, **adaptation_kwargs\n):\n    import blackjax\n\n    from blackjax.adaptation.base import get_filter_adapt_info_fn\n\n    algorithm_name = adaptation_kwargs.pop("algorithm", "nuts")\n    if algorithm_name == "nuts":\n        algorithm = blackjax.nuts\n    elif algorithm_name == "hmc":\n        algorithm = blackjax.hmc\n    else:\n        raise ValueError("Only supporting \'nuts\' or \'hmc\' as algorithm to draw samples.")\n\n    adapt = blackjax.window_adaptation(\n        algorithm=algorithm,\n        logdensity_fn=logp_fn,\n        target_acceptance_rate=target_accept,\n        adaptation_info_fn=get_filter_adapt_info_fn(),\n        **adaptation_kwargs,\n    )\n    (last_state, tuned_params), _ = adapt.run(seed, init_position, num_steps=tune)\n    kernel = algorithm(logp_fn, **tuned_params).step\n\n    def _one_step(state, xs):\n        _, rng_key = xs\n        state, info = kernel(rng_key, state)\n        position = state.position\n        stats = {\n            "diverging": info.is_divergent,\n            "energy": info.energy,\n            "tree_depth": info.num_trajectory_expansions,\n            "n_steps": info.num_integration_steps,\n            "acceptance_rate": info.acceptance_rate,\n            "lp": state.logdensity,\n        }\n        return state, (position, stats)\n\n    progress_bar = adaptation_kwargs.pop("progress_bar", False)\n\n    keys = jax.random.split(seed, draws)\n    scan_fn = blackjax.progress_bar.gen_scan_fn(draws, progress_bar)\n    _, (samples, stats) = scan_fn(_one_step, last_state, (jnp.arange(draws), keys))\n\n    return samples, stats\n\n\ndef _sample_blackjax_nuts(\n    model: Model,\n    target_accept: float,\n    tune: int,\n    draws: int,\n    chains: int,\n    chain_method: Literal["parallel", "vectorized"],\n    progressbar: bool,\n    random_seed: int,\n    initial_points: np.ndarray | list[np.ndarray],\n    nuts_kwargs: dict[str, Any],\n    logp_fn: Callable[[ArrayLike], jax.Array] | None = None,\n) -> tuple[Any, dict[str, Any], ModuleType]:\n    """\n    Draw samples from the posterior using the NUTS method from the ``blackjax`` library.\n\n    Parameters\n    ----------\n    model : Model\n        Model to sample from. The model needs to have free random variables.\n    target_accept : float in [0, 1].\n        The step size is tuned such that we approximate this acceptance rate. Higher\n        values like 0.9 or 0.95 often work better for problematic posteriors.\n    tune : int\n        Number of iterations to tune. Samplers adjust the step sizes, scalings or\n        similar during tuning. Tuning samples will be drawn in addition to the number\n        specified in the ``draws`` argument.\n    draws : int\n        The number of samples to draw. The number of tuned samples are discarded by default.\n    chains : int\n        The number of chains to sample.\n    chain_method : "parallel" or "vectorized"\n        Specify how samples should be drawn.\n    progressbar : bool\n        Whether to show progressbar or not during sampling.\n    random_seed : int, RandomState or Generator\n        Random seed used by the sampling steps.\n    initial_points : np.ndarray or list[np.ndarray]\n        Initial point(s) for sampler to begin sampling from.\n    nuts_kwargs : dict\n        Keyword arguments for the blackjax nuts sampler\n    logp_fn : Callable[[ArrayLike], jax.Array], optional, default None\n        jaxified logp function. If not passed in it will be created anew.\n\n    Returns\n    -------\n        raw_mcmc_samples\n            Datastructure containing raw mcmc samples\n        sample_stats : dict[str, Any]\n            Dictionary containing sample stats\n        blackjax : ModuleType["blackjax"]\n    """\n    import blackjax\n\n    # Adapted from numpyro\n    if chain_method == "parallel":\n        map_fn = jax.pmap\n    elif chain_method == "vectorized":\n        map_fn = jax.vmap\n    else:\n        raise ValueError(\n            "Only supporting the following methods to draw chains: \'parallel\' or \'vectorized\'"\n        )\n\n    if chains == 1:\n        initial_points = [np.stack(init_state) for init_state in zip(initial_points)]\n\n    if logp_fn is None:\n        logp_fn = get_jaxified_logp(model)\n\n    seed = jax.random.PRNGKey(random_seed)\n    keys = jax.random.split(seed, chains)\n\n    nuts_kwargs["progress_bar"] = progressbar\n    get_posterior_samples = partial(\n        _blackjax_inference_loop,\n        logp_fn=logp_fn,\n        tune=tune,\n        draws=draws,\n        target_accept=target_accept,\n        **nuts_kwargs,\n    )\n\n    raw_mcmc_samples, sample_stats = map_fn(get_posterior_samples)(keys, initial_points)\n    return raw_mcmc_samples, sample_stats, blackjax\n\n\n# Adopted from arviz numpyro extractor\ndef _numpyro_stats_to_dict(posterior) -> dict[str, Any]:\n    """Extract sample_stats from NumPyro posterior."""\n    rename_key = {\n        "potential_energy": "lp",\n        "adapt_state.step_size": "step_size",\n        "num_steps": "n_steps",\n        "accept_prob": "acceptance_rate",\n    }\n    data = {}\n    for stat, value in posterior.get_extra_fields(group_by_chain=True).items():\n        if isinstance(value, dict | tuple):\n            continue\n        name = rename_key.get(stat, stat)\n        value = value.copy()\n        data[name] = value\n        if stat == "num_steps":\n            data["tree_depth"] = np.log2(value).astype(int) + 1\n    return data\n\n\ndef _sample_numpyro_nuts(\n    model: Model,\n    target_accept: float,\n    tune: int,\n    draws: int,\n    chains: int,\n    chain_method: Literal["parallel", "vectorized"],\n    progressbar: bool,\n    random_seed: int,\n    initial_points: np.ndarray | list[np.ndarray],\n    nuts_kwargs: dict[str, Any],\n    logp_fn: Callable[[ArrayLike], jax.Array] | None = None,\n) -> tuple[Any, dict[str, Any], ModuleType]:\n    """\n    Draw samples from the posterior using the NUTS method from the ``numpyro`` library.\n\n    Parameters\n    ----------\n    model : Model\n        Model to sample from. The model needs to have free random variables.\n    target_accept : float in [0, 1].\n        The step size is tuned such that we approximate this acceptance rate. Higher\n        values like 0.9 or 0.95 often work better for problematic posteriors.\n    tune : int\n        Number of iterations to tune. Samplers adjust the step sizes, scalings or\n        similar during tuning. Tuning samples will be drawn in addition to the number\n        specified in the ``draws`` argument.\n    draws : int\n        The number of samples to draw. The number of tuned samples are discarded by default.\n    chains : int\n        The number of chains to sample.\n    chain_method : "parallel" or "vectorized"\n        Specify how samples should be drawn.\n    progressbar : bool\n        Whether to show progressbar or not during sampling.\n    random_seed : int, RandomState or Generator\n        Random seed used by the sampling steps.\n    initial_points : np.ndarray or list[np.ndarray]\n        Initial point(s) for sampler to begin sampling from.\n    nuts_kwargs : dict\n        Keyword arguments for the underlying numpyro nuts sampler\n    logp_fn : Callable[[ArrayLike], jax.Array], optional, default None\n        jaxified logp function. If not passed in it will be created anew.\n\n    Returns\n    -------\n        raw_mcmc_samples\n            Datastructure containing raw mcmc samples\n        sample_stats : dict[str, Any]\n            Dictionary containing sample stats\n        numpyro : ModuleType["numpyro"]\n    """\n    import numpyro\n\n    from numpyro.infer import MCMC, NUTS\n\n    if logp_fn is None:\n        logp_fn = get_jaxified_logp(model, negative_logp=False)\n\n    nuts_kwargs.setdefault("adapt_step_size", True)\n    nuts_kwargs.setdefault("adapt_mass_matrix", True)\n    nuts_kwargs.setdefault("dense_mass", False)\n\n    nuts_kernel = NUTS(\n        potential_fn=logp_fn,\n        target_accept_prob=target_accept,\n        **nuts_kwargs,\n    )\n\n    pmap_numpyro = MCMC(\n        nuts_kernel,\n        num_warmup=tune,\n        num_samples=draws,\n        num_chains=chains,\n        postprocess_fn=None,\n        chain_method=chain_method,\n        progress_bar=progressbar,\n    )\n\n    map_seed = jax.random.PRNGKey(random_seed)\n    if chains > 1:\n        map_seed = jax.random.split(map_seed, chains)\n\n    pmap_numpyro.run(\n        map_seed,\n        init_params=initial_points,\n        extra_fields=(\n            "num_steps",\n            "potential_energy",\n            "energy",\n            "adapt_state.step_size",\n            "accept_prob",\n            "diverging",\n        ),\n    )\n\n    raw_mcmc_samples = pmap_numpyro.get_samples(group_by_chain=True)\n    sample_stats = _numpyro_stats_to_dict(pmap_numpyro)\n    return raw_mcmc_samples, sample_stats, numpyro\n\n\ndef sample_jax_nuts(\n    draws: int = 1000,\n    *,\n    tune: int = 1000,\n    chains: int = 4,\n    target_accept: float = 0.8,\n    random_seed: RandomState | None = None,\n    initvals: StartDict | Sequence[StartDict | None] | None = None,\n    jitter: bool = True,\n    model: Model | None = None,\n    var_names: Sequence[str] | None = None,\n    nuts_kwargs: dict | None = None,\n    progressbar: bool = True,\n    keep_untransformed: bool = False,\n    chain_method: Literal["parallel", "vectorized"] = "parallel",\n    postprocessing_backend: Literal["cpu", "gpu"] | None = None,\n    postprocessing_vectorize: Literal["vmap", "scan"] | None = None,\n    postprocessing_chunks=None,\n    idata_kwargs: dict | None = None,\n    compute_convergence_checks: bool = True,\n    nuts_sampler: Literal["numpyro", "blackjax"],\n) -> az.InferenceData:\n    """\n    Draw samples from the posterior using a jax NUTS method.\n\n    Parameters\n    ----------\n    draws : int, default 1000\n        The number of samples to draw. The number of tuned samples are discarded by\n        default.\n    tune : int, default 1000\n        Number of iterations to tune. Samplers adjust the step sizes, scalings or\n        similar during tuning. Tuning samples will be drawn in addition to the number\n        specified in the ``draws`` argument.  Tuned samples are discarded.\n    chains : int, default 4\n        The number of chains to sample.\n    target_accept : float in [0, 1].\n        The step size is tuned such that we approximate this acceptance rate. Higher\n        values like 0.9 or 0.95 often work better for problematic posteriors.\n    random_seed : int, RandomState or Generator, optional\n        Random seed used by the sampling steps.\n    initvals: StartDict or Sequence[Optional[StartDict]], optional\n        Initial values for random variables provided as a dictionary (or sequence of\n        dictionaries) mapping the random variable (by name or reference) to desired\n        starting values.\n    jitter: bool, default True\n        If True, add jitter to initial points.\n    model : Model, optional\n        Model to sample from. The model needs to have free random variables. When inside\n        a ``with`` model context, it defaults to that model, otherwise the model must be\n        passed explicitly.\n    var_names : sequence of str, optional\n        Names of variables for which to compute the posterior samples. Defaults to all\n        variables in the posterior.\n    nuts_kwargs : dict, optional\n        Keyword arguments for the underlying nuts sampler\n    progressbar : bool, default True\n        If True, display a progressbar while sampling\n    keep_untransformed : bool, default False\n        Include untransformed variables in the posterior samples.\n    chain_method : Literal["parallel", "vectorized"], default "parallel"\n        Specify how samples should be drawn. The choices include "parallel", and\n        "vectorized".\n    postprocessing_backend : Optional[Literal["cpu", "gpu"]], default None,\n        Specify how postprocessing should be computed. gpu or cpu\n    postprocessing_vectorize : Literal["vmap", "scan"], default "scan"\n        How to vectorize the postprocessing: vmap or sequential scan\n    postprocessing_chunks : None\n        This argument is deprecated\n    idata_kwargs : dict, optional\n        Keyword arguments for :func:`arviz.from_dict`. It also accepts a boolean as\n        value for the ``log_likelihood`` key to indicate that the pointwise log\n        likelihood should not be included in the returned object. Values for\n        ``observed_data``, ``constant_data``, ``coords``, and ``dims`` are inferred from\n        the ``model`` argument if not provided in ``idata_kwargs``. If ``coords`` and\n        ``dims`` are provided, they are used to update the inferred dictionaries.\n    compute_convergence_checks : bool, default True\n        If True, compute ess and rhat values and warn if they indicate potential sampling issues.\n    nuts_sampler : Literal["numpyro", "blackjax"]\n        Nuts sampler library to use - do not change - use sample_numpyro_nuts or\n        sample_blackjax_nuts as appropriate\n\n    Returns\n    -------\n    InferenceData\n        ArviZ ``InferenceData`` object that contains the posterior samples, together\n        with their respective sample stats and pointwise log likeihood values (unless\n        skipped with ``idata_kwargs``).\n    """\n    if postprocessing_chunks is not None:\n        import warnings\n\n        warnings.warn(\n            "postprocessing_chunks is deprecated due to being unstable, "\n            "using postprocessing_vectorize=\'scan\' instead",\n            DeprecationWarning,\n        )\n\n    if postprocessing_vectorize is not None:\n        import warnings\n\n        warnings.warn(\n            \'postprocessing_vectorize={"scan", "vmap"} will be removed in a future release.\',\n            FutureWarning,\n        )\n    else:\n        postprocessing_vectorize = "vmap"\n\n    model = modelcontext(model)\n\n    if var_names is not None:\n        filtered_var_names = [v for v in model.unobserved_value_vars if v.name in var_names]\n    else:\n        filtered_var_names = model.unobserved_value_vars\n\n    if nuts_kwargs is None:\n        nuts_kwargs = {}\n    else:\n        nuts_kwargs = nuts_kwargs.copy()\n\n    vars_to_sample = list(\n        get_default_varnames(filtered_var_names, include_transformed=keep_untransformed)\n    )\n\n    if nuts_sampler == "numpyro":\n        sampler_fn = _sample_numpyro_nuts\n        logp_fn = get_jaxified_logp(model, negative_logp=False)\n    elif nuts_sampler == "blackjax":\n        sampler_fn = _sample_blackjax_nuts\n        logp_fn = get_jaxified_logp(model)\n    else:\n        raise ValueError(f"{nuts_sampler=} not recognized")\n\n    (random_seed,) = _get_seeds_per_chain(random_seed, 1)\n\n    initial_points = _get_batched_jittered_initial_points(\n        model=model,\n        chains=chains,\n        initvals=initvals,\n        random_seed=random_seed,\n        jitter=jitter,\n        logp_fn=logp_fn,\n    )\n\n    tic1 = datetime.now()\n    raw_mcmc_samples, sample_stats, library = sampler_fn(\n        model=model,\n        target_accept=target_accept,\n        tune=tune,\n        draws=draws,\n        chains=chains,\n        chain_method=chain_method,\n        progressbar=progressbar,\n        random_seed=random_seed,\n        initial_points=initial_points,\n        nuts_kwargs=nuts_kwargs,\n        logp_fn=logp_fn,\n    )\n    tic2 = datetime.now()\n\n    if idata_kwargs is None:\n        idata_kwargs = {}\n    else:\n        idata_kwargs = idata_kwargs.copy()\n\n    if idata_kwargs.pop("log_likelihood", False):\n        log_likelihood = _get_log_likelihood(\n            model,\n            raw_mcmc_samples,\n            backend=postprocessing_backend,\n            postprocessing_vectorize=postprocessing_vectorize,\n        )\n    else:\n        log_likelihood = None\n\n    jax_fn = get_jaxified_graph(inputs=model.value_vars, outputs=vars_to_sample)\n    result = _postprocess_samples(\n        jax_fn,\n        raw_mcmc_samples,\n        postprocessing_backend=postprocessing_backend,\n        postprocessing_vectorize=postprocessing_vectorize,\n        donate_samples=True,\n    )\n    del raw_mcmc_samples\n    mcmc_samples = {v.name: r for v, r in zip(vars_to_sample, result)}\n\n    attrs = {\n        "sampling_time": (tic2 - tic1).total_seconds(),\n        "tuning_steps": tune,\n    }\n\n    coords, dims = coords_and_dims_for_inferencedata(model)\n    # Update \'coords\' and \'dims\' extracted from the model with user \'idata_kwargs\'\n    # and drop keys \'coords\' and \'dims\' from \'idata_kwargs\' if present.\n    if "coords" in idata_kwargs:\n        coords.update(idata_kwargs.pop("coords"))\n    if "dims" in idata_kwargs:\n        dims.update(idata_kwargs.pop("dims"))\n\n    # Use \'partial\' to set default arguments before passing \'idata_kwargs\'\n    to_trace = partial(\n        az.from_dict,\n        log_likelihood=log_likelihood,\n        observed_data=find_observations(model),\n        constant_data=find_constants(model),\n        sample_stats=sample_stats,\n        coords=coords,\n        dims=dims,\n        attrs=make_attrs(attrs, library=library),\n        posterior_attrs=make_attrs(attrs, library=library),\n    )\n    az_trace = to_trace(posterior=mcmc_samples, **idata_kwargs)\n\n    if compute_convergence_checks:\n        warns = run_convergence_checks(az_trace, model)\n        log_warnings(warns)\n\n    return az_trace\n\n\nsample_numpyro_nuts = partial(sample_jax_nuts, nuts_sampler="numpyro")\nsample_blackjax_nuts = partial(sample_jax_nuts, nuts_sampler="blackjax")\n',
            'tests/sampling/test_jax.py': '#   Copyright 2024 - present The PyMC Developers\n#\n#   Licensed under the Apache License, Version 2.0 (the "License");\n#   you may not use this file except in compliance with the License.\n#   You may obtain a copy of the License at\n#\n#       http://www.apache.org/licenses/LICENSE-2.0\n#\n#   Unless required by applicable law or agreed to in writing, software\n#   distributed under the License is distributed on an "AS IS" BASIS,\n#   WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n#   See the License for the specific language governing permissions and\n#   limitations under the License.\nimport logging\nimport re\nimport warnings\n\nfrom collections.abc import Callable\nfrom typing import Any\nfrom unittest import mock\n\nimport arviz as az\nimport jax\nimport jax.numpy as jnp\nimport numpy as np\nimport pytensor\nimport pytensor.tensor as pt\nimport pytest\n\nfrom numpyro.infer import MCMC\nfrom pytensor.compile import SharedVariable\nfrom pytensor.graph import graph_inputs\n\nimport pymc as pm\n\nfrom pymc import ImputationWarning\nfrom pymc.distributions.multivariate import DirichletMultinomial, PosDefMatrix\nfrom pymc.model.transform.optimization import freeze_dims_and_data\nfrom pymc.sampling.jax import (\n    _get_batched_jittered_initial_points,\n    _get_log_likelihood,\n    _replace_shared_variables,\n    get_jaxified_graph,\n    get_jaxified_logp,\n    sample_blackjax_nuts,\n    sample_numpyro_nuts,\n)\n\n\ndef test_jax_PosDefMatrix():\n    x = pt.tensor(name="x", shape=(2, 2), dtype="float32")\n    matrix_pos_def = PosDefMatrix()\n    x_is_pos_def = matrix_pos_def(x)\n    f = pytensor.function(inputs=[x], outputs=[x_is_pos_def], mode="JAX")\n\n    test_cases = [\n        (jnp.eye(2), True),\n        (jnp.zeros(shape=(2, 2)), False),\n        (jnp.array([[1, -1.5], [0, 1.2]], dtype="float32"), True),\n        (-1 * jnp.array([[1, -1.5], [0, 1.2]], dtype="float32"), False),\n        (jnp.array([[1, -1.5], [0, -1.2]], dtype="float32"), False),\n    ]\n\n    for input, expected in test_cases:\n        actual = f(input)[0]\n        assert jnp.array_equal(a1=actual, a2=expected)\n\n\n@pytest.mark.parametrize(\n    "sampler",\n    [\n        sample_blackjax_nuts,\n        sample_numpyro_nuts,\n    ],\n)\n@pytest.mark.parametrize("postprocessing_backend", [None, "cpu"])\n@pytest.mark.parametrize(\n    "chains",\n    [\n        pytest.param(1),\n        pytest.param(\n            2, marks=pytest.mark.skipif(len(jax.devices()) < 2, reason="not enough devices")\n        ),\n    ],\n)\n@pytest.mark.parametrize("postprocessing_vectorize", ["scan", "vmap"])\ndef test_transform_samples(sampler, postprocessing_backend, chains, postprocessing_vectorize):\n    pytensor.config.on_opt_error = "raise"\n    np.random.seed(13244)\n\n    obs = np.random.normal(10, 2, size=100)\n    obs_at = pytensor.shared(obs, borrow=True, name="obs")\n    with pm.Model() as model:\n        a = pm.Uniform("a", -20, 20)\n        sigma = pm.HalfNormal("sigma", shape=(2,))\n        b = pm.Normal("b", a, sigma=sigma.mean(), observed=obs_at)\n\n        trace = sampler(\n            chains=chains,\n            random_seed=1322,\n            keep_untransformed=True,\n            postprocessing_backend=postprocessing_backend,\n            postprocessing_vectorize=postprocessing_vectorize,\n        )\n\n    log_vals = trace.posterior["sigma_log__"].values\n\n    trans_vals = trace.posterior["sigma"].values\n    assert np.allclose(np.exp(log_vals), trans_vals)\n\n    assert 8 < trace.posterior["a"].mean() < 11\n    assert 1.5 < trace.posterior["sigma"].mean() < 2.5\n\n    obs_at.set_value(-obs)\n    with model:\n        trace = sampler(\n            chains=chains,\n            random_seed=1322,\n            keep_untransformed=False,\n            postprocessing_backend=postprocessing_backend,\n        )\n\n    assert -11 < trace.posterior["a"].mean() < -8\n    assert 1.5 < trace.posterior["sigma"].mean() < 2.5\n\n\n@pytest.mark.parametrize(\n    "sampler",\n    [\n        sample_blackjax_nuts,\n        sample_numpyro_nuts,\n    ],\n)\n@pytest.mark.skipif(len(jax.devices()) < 2, reason="not enough devices")\ndef test_deterministic_samples(sampler):\n    pytensor.config.on_opt_error = "raise"\n    np.random.seed(13244)\n\n    obs = np.random.normal(10, 2, size=100)\n    obs_at = pytensor.shared(obs, borrow=True, name="obs")\n    with pm.Model() as model:\n        a = pm.Uniform("a", -20, 20)\n        b = pm.Deterministic("b", a / 2.0)\n        c = pm.Normal("c", a, sigma=1.0, observed=obs_at)\n\n        trace = sampler(chains=2, random_seed=1322, keep_untransformed=True)\n\n    assert 8 < trace.posterior["a"].mean() < 11\n    assert np.allclose(trace.posterior["b"].values, trace.posterior["a"].values / 2)\n\n\n@pytest.mark.parametrize(\n    "sampler",\n    [\n        sample_blackjax_nuts,\n        sample_numpyro_nuts,\n    ],\n)\ndef test_initvals_without_jitter(sampler):\n    pytensor.config.on_opt_error = "raise"\n    np.random.seed(13244)\n\n    obs = np.random.normal(10, 2, size=100)\n    obs_at = pytensor.shared(obs, borrow=True, name="obs")\n    initvals = {"a": -3}\n    with pm.Model() as model:\n        a = pm.Uniform("a", -20, 20)\n        b = pm.Deterministic("b", a / 2.0)\n        c = pm.Normal("c", a, sigma=1.0, observed=obs_at)\n\n        trace1 = sampler(\n            chains=1,\n            tune=1,\n            draws=1,\n            random_seed=1322,\n            initvals=initvals,\n            jitter=False,\n            keep_untransformed=True,\n        )\n        trace2 = sampler(\n            chains=1,\n            tune=1,\n            draws=1,\n            random_seed=1322,\n            initvals=initvals,\n            keep_untransformed=True,\n        )\n\n    assert np.allclose(trace1.posterior["a"].values[0], -3)\n    assert not np.allclose(trace2.posterior["a"].values[0], -3)\n\n\ndef test_get_jaxified_graph():\n    # Check that jaxifying a graph does not emit the Supervisor Warning. This test can\n    # be removed once https://github.com/aesara-devs/aesara/issues/637 is sorted.\n    x = pt.scalar("x")\n    y = pt.exp(x)\n    with warnings.catch_warnings():\n        warnings.simplefilter("error")\n        fn = get_jaxified_graph(inputs=[x], outputs=[y])\n    assert np.isclose(fn(0), 1)\n\n\ndef test_get_log_likelihood():\n    obs = np.random.normal(10, 2, size=100)\n    obs_at = pytensor.shared(obs, borrow=True, name="obs")\n    with pm.Model() as model:\n        a = pm.Normal("a", 0, 2)\n        sigma = pm.HalfNormal("sigma")\n        b = pm.Normal("b", a, sigma=sigma, observed=obs_at)\n\n        with warnings.catch_warnings():\n            warnings.filterwarnings("ignore", ".*number of samples.*", UserWarning)\n            trace = pm.sample(\n                tune=10,\n                draws=10,\n                chains=2,\n                random_seed=1322,\n                idata_kwargs={"log_likelihood": True},\n            )\n\n    b_true = trace.log_likelihood.b.values\n    a = np.array(trace.posterior.a)\n    sigma_log_ = np.log(np.array(trace.posterior.sigma))\n    b_jax = _get_log_likelihood(model, [a, sigma_log_])["b"]\n\n    assert np.allclose(b_jax.reshape(-1), b_true.reshape(-1))\n\n\ndef test_replace_shared_variables():\n    x = pytensor.shared(5, name="shared_x")\n\n    new_x = _replace_shared_variables([x])\n    shared_variables = [var for var in graph_inputs(new_x) if isinstance(var, SharedVariable)]\n    assert not shared_variables\n\n    x.default_update = x + 1\n    with pytest.raises(ValueError, match="shared variables with default_update"):\n        _replace_shared_variables([x])\n\n    shared_rng = pytensor.shared(np.random.default_rng(), name="shared_rng")\n    x = pytensor.tensor.random.normal(rng=shared_rng)\n    with pytest.raises(ValueError, match="Graph contains shared RandomType variables"):\n        _replace_shared_variables([x])\n\n\ndef test_get_jaxified_logp():\n    with pm.Model() as m:\n        x = pm.Flat("x")\n        y = pm.Flat("y")\n        pm.Potential("pot", pt.log(pt.exp(x) + pt.exp(y)))\n\n    jax_fn = get_jaxified_logp(m)\n    # This would underflow if not optimized\n    assert not np.isinf(jax_fn((np.array(5000.0), np.array(5000.0))))\n\n\n@pytest.fixture(scope="module")\ndef model_test_idata_kwargs() -> pm.Model:\n    with pm.Model(\n        coords={"x_coord": ["a", "b"], "x_coord2": [1, 2], "z_coord": ["apple", "banana", "orange"]}\n    ) as m:\n        x = pm.Normal("x", shape=(2,), dims=["x_coord"])\n        _ = pm.Normal("y", x, observed=[0, 0])\n        _ = pm.Normal("z", 0, 1, dims="z_coord")\n        pm.Data("data", [1, 2, 3])\n    return m\n\n\n@pytest.mark.parametrize(\n    "sampler",\n    [\n        sample_blackjax_nuts,\n        sample_numpyro_nuts,\n    ],\n)\n@pytest.mark.parametrize(\n    "idata_kwargs",\n    [\n        {},\n        {"log_likelihood": True},\n        # Overwrite models coords\n        {"coords": {"x_coord": ["x1", "x2"]}},\n        # Overwrite dims from dist specification in model\n        {"dims": {"x": ["x_coord2"]}},\n        # Overwrite both coords and dims\n        {"coords": {"x_coord3": ["A", "B"]}, "dims": {"x": ["x_coord3"]}},\n    ],\n)\n@pytest.mark.parametrize("postprocessing_backend", [None, "cpu"])\ndef test_idata_kwargs(\n    model_test_idata_kwargs: pm.Model,\n    sampler: Callable[..., az.InferenceData],\n    idata_kwargs: dict[str, Any],\n    postprocessing_backend: str | None,\n):\n    idata: az.InferenceData | None = None\n    with model_test_idata_kwargs:\n        idata = sampler(\n            tune=50,\n            draws=50,\n            chains=1,\n            idata_kwargs=idata_kwargs,\n            postprocessing_backend=postprocessing_backend,\n        )\n    assert idata is not None\n    const_data = idata.get("constant_data")\n    assert const_data is not None\n    assert "data" in const_data\n\n    if idata_kwargs.get("log_likelihood", False):\n        assert "log_likelihood" in idata\n    else:\n        assert "log_likelihood" not in idata\n\n    posterior = idata.get("posterior")\n    assert posterior is not None\n    x_dim_expected = idata_kwargs.get("dims", model_test_idata_kwargs.named_vars_to_dims)["x"][0]\n    assert x_dim_expected is not None\n    assert posterior["x"].dims[-1] == x_dim_expected\n\n    x_coords_expected = idata_kwargs.get("coords", model_test_idata_kwargs.coords)[x_dim_expected]\n    assert x_coords_expected is not None\n    assert list(x_coords_expected) == list(posterior["x"].coords[x_dim_expected].values)\n\n    assert posterior["z"].dims[2] == "z_coord"\n    assert np.all(\n        posterior["z"].coords["z_coord"].values == np.array(["apple", "banana", "orange"])\n    )\n\n\ndef test_get_batched_jittered_initial_points():\n    with pm.Model() as model:\n        x = pm.MvNormal("x", mu=np.zeros(3), cov=np.eye(3), shape=(2, 3), initval=np.zeros((2, 3)))\n\n    # No jitter\n    ips = _get_batched_jittered_initial_points(\n        model=model, chains=1, random_seed=1, initvals=None, jitter=False\n    )\n    assert np.all(ips[0] == 0)\n\n    # Single chain\n    ips = _get_batched_jittered_initial_points(model=model, chains=1, random_seed=1, initvals=None)\n\n    assert ips[0].shape == (2, 3)\n    assert np.all(ips[0] != 0)\n\n    # Multiple chains\n    ips = _get_batched_jittered_initial_points(model=model, chains=2, random_seed=1, initvals=None)\n\n    assert ips[0].shape == (2, 2, 3)\n    assert np.all(ips[0][0] != ips[0][1])\n\n\n@pytest.mark.parametrize(\n    "sampler",\n    [\n        sample_blackjax_nuts,\n        sample_numpyro_nuts,\n    ],\n)\n@pytest.mark.parametrize("random_seed", (None, 123))\n@pytest.mark.parametrize(\n    "chains",\n    [\n        pytest.param(1),\n        pytest.param(\n            2, marks=pytest.mark.skipif(len(jax.devices()) < 2, reason="not enough devices")\n        ),\n    ],\n)\ndef test_seeding(chains, random_seed, sampler):\n    sample_kwargs = {\n        "tune": 100,\n        "draws": 5,\n        "chains": chains,\n        "random_seed": random_seed,\n    }\n\n    with pm.Model() as m:\n        pm.Normal("x", mu=0, sigma=1)\n        result1 = sampler(**sample_kwargs)\n        result2 = sampler(**sample_kwargs)\n\n    all_equal = np.all(result1.posterior["x"] == result2.posterior["x"])\n    if random_seed is None:\n        assert not all_equal\n    else:\n        assert all_equal\n\n    if chains > 1:\n        assert np.all(result1.posterior["x"].sel(chain=0) != result1.posterior["x"].sel(chain=1))\n        assert np.all(result2.posterior["x"].sel(chain=0) != result2.posterior["x"].sel(chain=1))\n\n\n@mock.patch("numpyro.infer.MCMC")\ndef test_numpyro_nuts_kwargs_are_used(mocked: mock.MagicMock):\n    mocked.side_effect = MCMC\n\n    step_size = 0.13\n    dense_mass = True\n    adapt_step_size = False\n    target_accept = 0.78\n\n    with pm.Model():\n        pm.Normal("a")\n        sample_numpyro_nuts(\n            10,\n            tune=10,\n            chains=1,\n            target_accept=target_accept,\n            nuts_kwargs={\n                "step_size": step_size,\n                "dense_mass": dense_mass,\n                "adapt_step_size": adapt_step_size,\n            },\n        )\n    mocked.assert_called_once()\n    nuts_sampler = mocked.call_args.args[0]\n    assert nuts_sampler._step_size == step_size\n    assert nuts_sampler._dense_mass == dense_mass\n    assert nuts_sampler._adapt_step_size == adapt_step_size\n    assert nuts_sampler._adapt_mass_matrix\n    assert nuts_sampler._target_accept_prob == target_accept\n\n\n@pytest.mark.parametrize(\n    "sampler_name",\n    [\n        "sample_blackjax_nuts",\n        "sample_numpyro_nuts",\n    ],\n)\ndef test_idata_contains_stats(sampler_name: str):\n    """Tests whether sampler statistics were written to sample_stats\n    group of InferenceData"""\n    if sampler_name == "sample_blackjax_nuts":\n        sampler = sample_blackjax_nuts\n    elif sampler_name == "sample_numpyro_nuts":\n        sampler = sample_numpyro_nuts\n\n    with pm.Model():\n        pm.Normal("a")\n        idata = sampler(tune=50, draws=50)\n\n    stats = idata.get("sample_stats")\n    assert stats is not None\n    n_chains = stats.sizes["chain"]\n    n_draws = stats.sizes["draw"]\n\n    # Stats vars expected for both samplers\n    expected_stat_vars = {\n        "acceptance_rate": (n_chains, n_draws),\n        "diverging": (n_chains, n_draws),\n        "energy": (n_chains, n_draws),\n        "tree_depth": (n_chains, n_draws),\n        "lp": (n_chains, n_draws),\n    }\n    # Stats only expected for blackjax nuts\n    if sampler_name == "sample_blackjax_nuts":\n        blackjax_special_vars = {}\n        stat_vars = expected_stat_vars | blackjax_special_vars\n    # Stats only expected for numpyro nuts\n    elif sampler_name == "sample_numpyro_nuts":\n        numpyro_special_vars = {\n            "step_size": (n_chains, n_draws),\n            "n_steps": (n_chains, n_draws),\n        }\n        stat_vars = expected_stat_vars | numpyro_special_vars\n    # test existence and dimensionality\n    for stat_var, stat_var_dims in stat_vars.items():\n        assert stat_var in stats.variables\n        assert stats.get(stat_var).values.shape == stat_var_dims\n\n\ndef test_sample_partially_observed():\n    with pm.Model() as m:\n        with pytest.warns(ImputationWarning):\n            x = pm.Normal("x", observed=np.array([0, 1, np.nan]))\n        idata = pm.sample(nuts_sampler="numpyro", chains=1, draws=10, tune=10)\n\n    assert idata.observed_data["x_observed"].shape == (2,)\n    assert idata.posterior["x_unobserved"].shape == (1, 10, 1)\n    assert idata.posterior["x"].shape == (1, 10, 3)\n\n\ndef test_sample_var_names():\n    with pm.Model() as model:\n        a = pm.Normal("a")\n        b = pm.Deterministic("b", a**2)\n        idata = pm.sample(10, tune=10, nuts_sampler="numpyro", var_names=["a"])\n        assert "a" in idata.posterior\n        assert "b" not in idata.posterior\n\n\n@pytest.mark.parametrize("nuts_sampler", ("numpyro", "blackjax"))\ndef test_convergence_warnings(caplog, nuts_sampler):\n    with pm.Model() as m:\n        # Model that should diverge\n        sigma = pm.Normal("sigma", initval=3, default_transform=None)\n        pm.Normal("obs", mu=0, sigma=sigma, observed=[0.99, 1.0, 1.01])\n\n        with caplog.at_level(logging.WARNING, logger="pymc"):\n            pm.sample(nuts_sampler=nuts_sampler, random_seed=581)\n\n    [record] = caplog.records\n    assert re.match(r"There were \\d+ divergences after tuning", record.message)\n\n\ndef test_dirichlet_multinomial():\n    """Test we can draw from a DM in the JAX backend if the shape is constant."""\n    dm = DirichletMultinomial.dist(n=5, a=np.eye(3) * 1e6 + 0.01)\n    dm_draws = pm.draw(dm, mode="JAX")\n    np.testing.assert_equal(dm_draws, np.eye(3) * 5)\n\n\ndef test_dirichlet_multinomial_dims():\n    """Test we can draw from a DM with a shape defined by dims in the JAX backend,\n    after freezing those dims.\n    """\n    with pm.Model(coords={"trial": range(3), "item": range(3)}) as m:\n        dm = DirichletMultinomial("dm", n=5, a=np.eye(3) * 1e6 + 0.01, dims=("trial", "item"))\n\n    # JAX does not allow us to JIT a function with dynamic shape\n    with pytest.raises(TypeError):\n        pm.draw(dm, mode="JAX")\n\n    # Should be fine after freezing the dims that specify the shape\n    frozen_dm = freeze_dims_and_data(m)["dm"]\n    dm_draws = pm.draw(frozen_dm, mode="JAX")\n    np.testing.assert_equal(dm_draws, np.eye(3) * 5)\n',
        }
